1185→    // Save interpreter state that the parent's evaluation will corrupt.
1186→    // These are effectively "callee-saved registers" of the interpreter —
1187→    // the coro's evaluation expects them to be preserved across the suspend.
1188→    // The parent shares the same Interp but modifies these fields when
1189→    // evaluating the shift body. We must restore them on resume.
1190→    Env*       saved_jit_env    = interp.jit_env;
1191→    Env*       saved_match_env  = interp.match_env;
1192→    usz        saved_eval_depth = interp.eval_depth;
