1201→    // Suspend the coro — control returns to jit_reset_impl
1202→    main::stack_ctx_suspend();
1203→
1204→    // === RESUMED HERE by (k val) via jit_apply_continuation_impl ===
1205→    // Restore interpreter state (corrupted by parent's evaluation of shift body)
1206→    interp.jit_env = saved_jit_env;
1207→    interp.match_env = saved_match_env;

